import asyncio
import websockets
import json
from collections import defaultdict

class GameServer:
    def __init__(self):
        self.players = {}
        self.inventory = defaultdict(dict)

    async def register(self, websocket):
        self.players[websocket] = None

    async def unregister(self, websocket):
        del self.players[websocket]

    async def handle_message(self, websocket, message):
        data = json.loads(message)
        action = data.get("action")

        if action == "register":
            await self.register_player(websocket, data)
        elif action == "trade":
            await self.handle_trade(websocket, data)

    async def register_player(self, websocket, data):
        player_id = data.get("player_id")
        self.players[websocket] = player_id
        self.inventory[player_id] = data.get("inventory", {})
        await self.send_inventory(websocket)

    async def handle_trade(self, websocket, data):
        from_player = self.players[websocket]
        to_player = data.get("to_player")
        item = data.get("item")

        if from_player and to_player in self.inventory:
            if item in self.inventory[from_player]:
                await self.execute_trade(from_player, to_player, item)

    async def execute_trade(self, from_player, to_player, item):
        if item in self.inventory[from_player]:
            self.inventory[to_player][item] = self.inventory[from_player].pop(item)
            await self.notify_players(from_player, to_player, item)

    async def notify_players(self, from_player, to_player, item):
        for websocket in self.players:
            if self.players[websocket] == from_player or self.players[websocket] == to_player:
                await websocket.send(json.dumps({
                    "action": "trade_complete",
                    "from": from_player,
                    "to": to_player,
                    "item": item
                }))
        await self.send_inventory(websockets)

    async def send_inventory(self, websocket):
        player_id = self.players[websocket]
        await websocket.send(json.dumps({
            "action": "inventory_update",
            "inventory": self.inventory[player_id]
        }))

    async def main(self, websocket, path):
        await self.register(websocket)
        try:
            async for message in websocket:
                await self.handle_message(websocket, message)
        finally:
            await self.unregister(websocket)

start_server = websockets.serve(GameServer().main, "localhost", 6789)

